  const audioRef = useRef<HTMLAudioElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [analyser, setAnalyser] = useState<AnalyserNode | null>(null);
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Inicjalizacja Web Audio API
  useEffect(() => {
    if (!audioRef.current) return;

    if (!audioContextRef.current) {
      // Lazy init context (browsers block autoplay if created too early)
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContextClass();
      const analyserNode = ctx.createAnalyser();
      analyserNode.fftSize = 256;

      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyserNode);
      analyserNode.connect(ctx.destination);

      audioContextRef.current = ctx;
      sourceNodeRef.current = source;
      analyserRef.current = analyserNode;
      setAnalyser(analyserNode);
    }
  }, [currentFile]); // Re-check when file changes, but ctx is singleton

  // Obsługa zmiany pliku
  useEffect(() => {
    setErrorMsg(null);
    if (currentFile) {
      // Zapobieganie próbie odtworzenia pustych plików z przywróconej sesji (rozmiar 0)
      if (currentFile.file.size === 0) {
          setErrorMsg("Plik niedostępny (Sesja przywrócona). Załaduj go ponownie.");
          setBlobUrl(null);
          return;
      }

      if (blobUrl) URL.revokeObjectURL(blobUrl);
      const newUrl = URL.createObjectURL(currentFile.file);
      setBlobUrl(newUrl);
    }
    return () => {
      if (blobUrl) URL.revokeObjectURL(blobUrl);
    };
  }, [currentFile?.id]); // Only change if ID changes

  // Sterowanie odtwarzaniem
  useEffect(() => {
    if (!audioRef.current) return;

    if (errorMsg || !blobUrl) {
        audioRef.current.pause();
        return;
    }

    if (audioRef.current.src !== blobUrl) {
       audioRef.current.src = blobUrl;
       audioRef.current.load();
    }

    if (isPlaying) {
      // Resume context if suspended (browser policy)
      if (audioContextRef.current?.state === 'suspended') {
        audioContextRef.current.resume();
      }

      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
          playPromise.catch(e => {
              console.error("Playback failed:", e);
              // Nie ustawiamy globalnego błędu od razu, bo czasem to kwestia autoodtwarzania
          });
