    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleError = (e: React.SyntheticEvent<HTMLAudioElement, Event>) => {
      console.error("Audio element error:", e);
      const target = e.target as HTMLAudioElement;
      let msg = "Błąd odtwarzania.";
      if (target.error) {
          switch(target.error.code) {
              case target.error.MEDIA_ERR_ABORTED: msg = "Przerwano pobieranie."; break;
              case target.error.MEDIA_ERR_NETWORK: msg = "Błąd sieci."; break;
              case target.error.MEDIA_ERR_DECODE: msg = "Błąd dekodowania pliku."; break;
              case target.error.MEDIA_ERR_SRC_NOT_SUPPORTED: msg = "Format nieobsługiwany lub brak źródła."; break;
          }
      }
      setErrorMsg(msg);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = Number(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  if (!currentFile) return null;

  const displayTags = currentFile.fetchedTags || currentFile.originalTags;
  const title = displayTags.title || currentFile.file.name;
