<content><![CDATA[import React, { useState, useEffect, useMemo } from 'react';
import { AudioFile, ID3Tags } from '../types';
import AlbumCover from './AlbumCover';

interface EditTagsModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (tags: ID3Tags) => void;
  onApply: (tags: ID3Tags) => void;
  file: AudioFile;
  onManualSearch: (query: string, file: AudioFile) => Promise<void>;
  onZoomCover: (imageUrl: string) => void;
  isApplying: boolean;
  isDirectAccessMode: boolean;
}

const EditTagsModal: React.FC<EditTagsModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onApply,
  file,
  onManualSearch,
  onZoomCover,
  isApplying,
  isDirectAccessMode,
}) => {
  const [tags, setTags] = useState<ID3Tags>({});
  const [manualQuery, setManualQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen && file) {
      setTags(file.fetchedTags || file.originalTags || {});
      setManualQuery(file.file.name);
      setSearchError(null);
    }
  }, [isOpen, file]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    setTags((prevTags) => ({
      ...prevTags,
      [name]: type === 'number' ? (value ? Number(value) : undefined) : value,
    }));
  };

  const handleSave = () => {
    onSave(tags);
  };

  const handleSearch = async () => {
    setIsSearching(true);
    setSearchError(null);
    try {
      await onManualSearch(manualQuery, file);
    } catch (error) {
      setSearchError(error instanceof Error ? error.message : "Wystąpił nieznany błąd wyszukiwania.");
    } finally {
      setIsSearching(false);
    }
  };

  useEffect(() => {
      if (file) {
          setTags(file.fetchedTags || file.originalTags || {});
      }
  }, [file?.fetchedTags]);

  const initialTags = useMemo(() => file.fetchedTags || file.originalTags || {}, [file.fetchedTags, file.originalTags]);
  const hasChanges = useMemo(() => JSON.stringify(tags) !== JSON.stringify(initialTags), [tags, initialTags]);

  if (!isOpen) return null;

  const tagFields: (keyof Omit<ID3Tags, 'albumCoverUrl' | 'comments'>)[] = [
    'title', 'artist', 'albumArtist', 'album', 'year', 'trackNumber', 'discNumber', 'genre', 'composer', 'originalArtist', 'mood', 'copyright', 'encodedBy', 'bitrate', 'sampleRate'
  ];
  const tagLabels: Record<string, string> = {
    title: 'Tytuł',
    artist: 'Wykonawca',
    albumArtist: 'Album Artist',
    album: 'Album',
    year: 'Rok',
    genre: 'Gatunek',
    mood: 'Mood',
    comments: 'Komentarze',
    bitrate: 'Bitrate',
    sampleRate: 'Sample Rate',
    trackNumber: 'Track #',
    discNumber: 'Disc #',
    composer: 'Kompozytor',
    copyright: 'Copyright',
    encodedBy: 'Encoder',
    originalArtist: 'Oryg. Wykonawca',
  };

  // Styles for inputs
  const inputClass = "mt-1 block w-full bg-[#0a0a0f] border border-white/10 rounded-lg py-2 px-3 text-white placeholder-slate-600 focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 sm:text-sm transition-all";
  const labelClass = "block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1";

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[60]" onClick={onClose}>
      <div 
        className="bg-[#1a1a2e] border border-white/10 rounded-2xl shadow-2xl p-0 w-full max-w-4xl mx-4 max-h-[90vh] overflow-hidden flex flex-col transform transition-all duration-300 animate-fade-in-scale" 
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="p-6 border-b border-white/5 bg-white/5 flex justify-between items-center">
            <div>
                <h2 className="text-xl font-bold text-white neon-text-blue">Edycja Metadanych</h2>
                <p className="text-xs text-slate-400 font-mono mt-1 truncate max-w-md" title={file.file.name}>
                  {file.file.name}
                </p>
            </div>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        <div className="p-6 overflow-y-auto custom-scrollbar flex-grow">
            {/* Manual Search Section */}
            <div className="mb-8 p-4 bg-indigo-900/10 border border-indigo-500/20 rounded-xl">
            <label htmlFor="manualQuery" className="block text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">
                Asystent AI
            </label>
            <div className="flex gap-2">
                <input
                type="text"
                id="manualQuery"
                value={manualQuery}
                onChange={(e) => setManualQuery(e.target.value)}
                className="flex-grow bg-[#0a0a0f] border border-indigo-500/30 rounded-lg py-2 px-3 text-white focus:outline-none focus:border-indigo-500 sm:text-sm placeholder-slate-600"
                placeholder="Wpisz Artystę i Tytuł..."
                />
                <button 
                    onClick={handleSearch} 
                    disabled={isSearching || !manualQuery} 
                    className="px-5 py-2 text-sm font-bold text-white bg-indigo-600 rounded-lg hover:bg-indigo-500 disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed flex items-center transition-all shadow-[0_0_15px_rgba(79,70,229,0.3)]"
                >
                {isSearching ? <span className="btn-spinner"></span> : 'SZUKAJ'}
                </button>
            </div>
            {searchError && <p className="text-xs text-red-400 mt-2">{searchError}</p>}
            </div>

            {/* Tags Form */}
            <div className="flex flex-col md:flex-row gap-8">
                {/* Left Col: Cover */}
                <div className="md:w-1/3 flex flex-col">
                    <div className="relative group cursor-pointer aspect-square w-full rounded-xl overflow-hidden border border-white/10 shadow-2xl" onClick={() => tags.albumCoverUrl && onZoomCover(tags.albumCoverUrl)}>
                        <AlbumCover tags={tags} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-sm">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" /></svg>
                        </div>
                    </div>

                    <div className="mt-4">
                        <label htmlFor="albumCoverUrl" className={labelClass}>URL Okładki</label>
                        <input
                        type="text"
                        name="albumCoverUrl"
                        id="albumCoverUrl"
                        value={tags.albumCoverUrl || ''}
                        onChange={handleChange}
                        className={inputClass}
                        placeholder="https://..."
                        />
                    </div>
                </div>

                {/* Right Col: Fields */}
                <div className="md:w-2/3">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {tagFields.map((key) => (
                        <div key={key} className={['title', 'album', 'copyright'].includes(key) ? 'sm:col-span-2' : ''}>
                        <label htmlFor={key} className={labelClass}>
                            {tagLabels[key]}
                        </label>
                        <input
                            type={key === 'bitrate' || key === 'sampleRate' ? 'number' : 'text'}
                            name={key}
                            id={key}
                            value={tags[key] || ''}
                            onChange={handleChange}
                            className={inputClass}
                        />
                        </div>
                    ))}
                    </div>
                    <div className="mt-4">
                    <label htmlFor="comments" className={labelClass}>{tagLabels['comments']}</label>
                        <textarea
                        name="comments"
                        id="comments"
                        value={tags.comments || ''}
                        onChange={handleChange}
                        rows={3}
                        className={inputClass}
                        />
                    </div>
                </div>
            </div>
        </div>

        {/* Footer Buttons */}
        <div className="p-6 border-t border-white/5 bg-[#0f0f16] flex justify-end gap-3">
          <button 
            onClick={onClose} 
            className="px-6 py-2.5 text-sm font-bold text-slate-400 hover:text-white hover:bg-white/5 rounded-lg transition-colors"
          >
            ANULUJ
          </button>

          {isDirectAccessMode && (
            <button 
              onClick={() => onApply(tags)} 
              disabled={isApplying || !hasChanges}
              className="px-6 py-2.5 text-sm font-bold text-white bg-green-600 rounded-lg hover:bg-green-500 disabled:bg-slate-700 disabled:text-slate-500 transition-all flex items-center shadow-[0_0_15px_rgba(22,163,74,0.3)]"
              title="Zapisz bezpośrednio do pliku"
            >
              {isApplying ? (
                  <><span className="btn-spinner !mr-2"></span><span>ZAPISUJĘ...</span></>
              ) : (
                  'ZAPISZ DO PLIKU'
              )}
            </button>
          )}

          <button 
            onClick={handleSave} 
            className="px-6 py-2.5 text-sm font-bold text-white bg-indigo-600 rounded-lg hover:bg-indigo-500 transition-all shadow-[0_0_15px_rgba(79,70,229,0.3)]"
          >
            OK (Pamięć)
          </button>
        </div>
      </div>
       <style>{`.animate-fade-in-scale { animation: fade-in-scale 0.2s ease-out forwards; } @keyframes fade-in-scale { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }`}</style>
    </div>
  );
};

export default EditTagsModal;]]></content>
