<description>Zmiana stylu listy duplikatów na spójny z Neon UI. Ciemne karty, kolorowe obramowania.</description>
<content><![CDATA[import React, { useState, useEffect } from 'react';
import { AudioFile, ID3Tags } from '../types';
import { findDuplicates, DuplicateGroup } from '../utils/duplicateUtils';
import AlbumCover from './AlbumCover';
import { StatusIcon } from './StatusIcon';

interface DuplicateFinderTabProps {
  files: AudioFile[];
  onDelete: (fileId: string) => void;
  onPlayPause: (fileId: string) => void;
  playingFileId: string | null;
  isPlaying: boolean;
}

const DuplicateFinderTab: React.FC<DuplicateFinderTabProps> = ({ 
  files, 
  onDelete, 
  onPlayPause, 
  playingFileId, 
  isPlaying 
}) => {
  const [groups, setGroups] = useState<DuplicateGroup[]>([]);
  const [isScanning, setIsScanning] = useState(false);
  const [scannedOnce, setScannedOnce] = useState(false);

  const handleScan = () => {
    setIsScanning(true);
    setTimeout(() => {
      const results = findDuplicates(files);
      setGroups(results);
      setIsScanning(false);
      setScannedOnce(true);
    }, 100);
  };

  const keepBest = (groupId: string, criteria: 'bitrate' | 'newest' | 'oldest') => {
    const group = groups.find(g => g.id === groupId);
    if (!group) return;

    let fileToKeep: AudioFile | null = null;

    if (criteria === 'bitrate') {
      fileToKeep = group.files.reduce((prev, current) => {
        const prevBitrate = prev.fetchedTags?.bitrate || prev.originalTags.bitrate || 0;
        const currBitrate = current.fetchedTags?.bitrate || current.originalTags.bitrate || 0;
        return (prevBitrate > currBitrate) ? prev : current;
      });
    } else if (criteria === 'newest') {
       fileToKeep = group.files.reduce((prev, current) => (prev.file.lastModified > current.file.lastModified ? prev : current));
    } else {
       fileToKeep = group.files.reduce((prev, current) => (prev.file.lastModified < current.file.lastModified ? prev : current));
    }

    if (fileToKeep) {
       group.files.forEach(f => {
           if (f.id !== fileToKeep!.id) {
               onDelete(f.id);
           }
       });
       setGroups(prev => prev.filter(g => g.id !== groupId));
    }
  };

  const ignoreGroup = (groupId: string) => {
      setGroups(prev => prev.filter(g => g.id !== groupId));
  }

  return (
    <div className="animate-fade-in p-6 pb-20 max-w-5xl mx-auto">
      <div className="text-center mb-8 bg-[#1a1a2e]/60 p-8 rounded-2xl border border-white/5 backdrop-blur-sm">
        <h2 className="text-3xl font-bold text-white mb-2 neon-text-blue">Wyszukiwarka Duplikatów</h2>
        <p className="text-slate-400 mb-8 max-w-lg mx-auto">
          Znajdź i usuń powtarzające się utwory, analizując nazwy plików, metadane oraz rozmiar plików.
        </p>
        <button
          onClick={handleScan}
          disabled={isScanning}
          className="px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-full shadow-[0_0_20px_rgba(79,70,229,0.3)] transition-transform transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed flex items-center mx-auto"
        >
          {isScanning ? (
              <>
