<content><![CDATA[import React, { useState } from 'react';
import { detectAndParseXML, ParsedLibrary } from '../utils/xmlParser';

const ConverterTab: React.FC = () => {
  const [parsedData, setParsedData] = useState<ParsedLibrary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);
    setParsedData(null);

    try {
      const data = await detectAndParseXML(file);
      setParsedData(data);
    } catch (err: any) {
      setError(err.message || "Wystąpił błąd podczas parsowania.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="animate-fade-in p-6 pb-20 max-w-4xl mx-auto">
      <div className="bg-[#1a1a2e]/60 p-10 rounded-2xl border border-white/5 backdrop-blur-sm text-center mb-8 shadow-neon-sm">
