            </svg>
            <span>WYBIERZ PLIK XML</span>
            <input type="file" accept=".xml" onChange={handleFileUpload} className="hidden" disabled={isProcessing} />
        </label>

        {isProcessing && <p className="mt-6 text-fuchsia-400 animate-pulse font-mono">ANALIZOWANIE PLIKU...</p>}
        {error && <p className="mt-6 text-red-500 font-bold bg-red-900/20 inline-block px-4 py-2 rounded-lg">{error}</p>}
      </div>

      {parsedData && (
        <div className="space-y-6 animate-slide-up">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
