                    <p className="text-2xl font-bold text-fuchsia-400 neon-text-pink">{parsedData.program}</p>
                </div>
                <div className="bg-[#1a1a2e] p-5 rounded-xl border border-white/5 flex flex-col items-center">
                    <h3 className="text-xs text-slate-500 uppercase font-bold tracking-widest mb-2">UTWORY</h3>
                    <p className="text-2xl font-bold text-white">{parsedData.tracks.length}</p>
                </div>
                <div className="bg-[#1a1a2e] p-5 rounded-xl border border-white/5 flex flex-col items-center">
                    <h3 className="text-xs text-slate-500 uppercase font-bold tracking-widest mb-2">PLAYLISTY</h3>
                    <p className="text-2xl font-bold text-white">{parsedData.playlists.length}</p>
                </div>
            </div>

            <div className="bg-[#1a1a2e] rounded-xl border border-white/5 overflow-hidden">
                <div className="p-4 border-b border-white/5 bg-white/5">
                    <h3 className="font-bold text-white">Znalezione Playlisty</h3>
                </div>
                <div className="max-h-80 overflow-y-auto custom-scrollbar">
                    {parsedData.playlists.length === 0 ? (
                        <p className="p-6 text-slate-500 italic text-center">Brak playlist w pliku.</p>
                    ) : (
                        <ul className="divide-y divide-white/5">
                            {parsedData.playlists.map((pl, idx) => (
                                <li key={idx} className="p-3 hover:bg-white/5 flex justify-between items-center transition-colors">
                                    <span className="text-sm font-medium text-slate-200">{pl.Name}</span>
                                    <span className="text-[10px] font-bold bg-white/10 text-slate-400 px-2 py-1 rounded">
                                        {pl.Tracks.length} utw.
                                    </span>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>
            </div>

            <div className="flex justify-end">
                 <button className="px-6 py-2.5 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-lg transition-colors border border-white/10" onClick={() => {
                     const json = JSON.stringify(parsedData, null, 2);
                     const blob = new Blob([json], {type: 'application/json'});
                     const url = URL.createObjectURL(blob);
                     const a = document.createElement('a');
                     a.href = url;
                     a.download = `converted_${parsedData.program.toLowerCase()}.json`;
                     a.click();
                 }}>
                     EKSPORTUJ DO JSON
                 </button>
            </div>
        </div>
      )}
    </div>
  );
};

export default ConverterTab;]]></content>
