      discNumber: '1',
      composer: 'Kompozytor',
      copyright: '© 2024 Wytwórnia',
      encodedBy: 'Encoder',
      originalArtist: 'Oryginalny Wykonawca'
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[70]" onClick={onClose}>
      <div 
        className="bg-[#1a1a2e] border border-white/10 rounded-2xl shadow-2xl p-0 w-full max-w-2xl mx-4 flex flex-col transform transition-all duration-300 animate-fade-in-scale overflow-hidden" 
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-6 border-b border-white/5 bg-white/5">
            <h2 className="text-xl font-bold text-white neon-text-blue">Zmień nazwy plików</h2>
            <p className="text-xs text-slate-400 mt-1">
              Zdefiniuj szablon używając tagów. Użyj <code>/</code> aby stworzyć foldery (np. <code>[artist]/[album]/[title]</code>).
            </p>
        </div>

        <div className="p-6 space-y-6">
            <div>
              <label htmlFor="pattern" className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">
                Szablon
              </label>
              <div className="relative">
                  <input
                    ref={inputRef}
                    type="text"
                    id="pattern"
                    value={pattern}
                    onChange={(e) => setPattern(e.target.value)}
                    className="block w-full bg-[#0a0a0f] border border-cyan-500/30 rounded-xl py-3 px-4 text-white placeholder-slate-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 font-mono text-sm shadow-[0_0_15px_rgba(34,211,238,0.1)] transition-all"
                    placeholder="[artist] - [title]"
                  />
              </div>
            </div>

            <div>
                <p className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Dostępne znaczniki:</p>
                <div className="flex flex-wrap gap-2">
                    {placeholders.map(p => (
                        <button 
                            key={p} 
                            onClick={() => insertPlaceholder(p)}
                            className="px-2 py-1 text-[10px] font-mono font-bold bg-indigo-900/30 text-indigo-300 border border-indigo-500/20 rounded hover:bg-indigo-500/20 hover:text-white hover:border-indigo-400 transition-all"
                        >
                            [{p}]
