                    <p className="text-xs font-bold text-slate-500 mb-1">PRZYKŁAD:</p>
                    <p className="text-sm text-cyan-400 font-mono break-all">
                        {generatePath(pattern, genericExampleTags, 'przyklad.mp3')}
                    </p>
                </div>
