import React, { useState } from 'react';
import { SmartPlaylistRule, SmartPlaylistRuleField, SmartPlaylistOperator } from '../types';

interface CreatePlaylistModalProps {
  isOpen: boolean;
  onClose: () => void;
  onCreateStandard: (name: string) => void;
  onCreateSmart: (name: string, rules: SmartPlaylistRule[]) => void;
}

const CreatePlaylistModal: React.FC<CreatePlaylistModalProps> = ({ isOpen, onClose, onCreateStandard, onCreateSmart }) => {
  const [mode, setMode] = useState<'standard' | 'smart'>('standard');
  const [name, setName] = useState('');
  const [rules, setRules] = useState<SmartPlaylistRule[]>([
    { id: '1', field: 'genre', operator: 'contains', value: '' }
  ]);

  if (!isOpen) return null;

  const handleCreate = () => {
    if (!name.trim()) return;

    if (mode === 'standard') {
      onCreateStandard(name.trim());
    } else {
      // Filter out incomplete rules
      const validRules = rules.filter(r => r.value.trim() !== '');
      if (validRules.length === 0) {
          alert("Dodaj przynajmniej jedną poprawną regułę.");
          return;
      }
      onCreateSmart(name.trim(), validRules);
    }
    onClose();
  };

  const addRule = () => {
    setRules([...rules, { id: Date.now().toString(), field: 'genre', operator: 'contains', value: '' }]);
  };

  const removeRule = (id: string) => {
    setRules(rules.filter(r => r.id !== id));
  };

  const updateRule = (id: string, updates: Partial<SmartPlaylistRule>) => {
    setRules(rules.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const fields: { value: SmartPlaylistRuleField, label: string }[] = [
      { value: 'artist', label: 'Artysta' },
      { value: 'title', label: 'Tytuł' },
      { value: 'album', label: 'Album' },
      { value: 'genre', label: 'Gatunek' },
      { value: 'year', label: 'Rok' },
      { value: 'bpm', label: 'BPM' },
      { value: 'key', label: 'Tonacja (Key)' },
  ];

  const operators: { value: SmartPlaylistOperator, label: string }[] = [
      { value: 'contains', label: 'zawiera' },
      { value: 'is', label: 'jest równe' },
      { value: 'isNot', label: 'nie jest równe' },
      { value: 'startsWith', label: 'zaczyna się od' },
      { value: 'greaterThan', label: 'większe niż (>)' },
      { value: 'lessThan', label: 'mniejsze niż (<)' },
  ];

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex justify-center items-center z-[80]" onClick={onClose}>
      <div 
        className="bg-[#1a1a2e] border border-white/10 rounded-2xl shadow-2xl p-0 w-full max-w-lg mx-4 transform transition-all duration-300 animate-fade-in-scale flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-6 border-b border-white/5 bg-white/5">
            <h2 className="text-xl font-bold text-white neon-text-blue">Nowa Playlista</h2>
        </div>

        <div className="p-6 space-y-6 overflow-y-auto custom-scrollbar">
            {/* Type Switcher */}
            <div className="flex bg-[#0a0a0f] p-1 rounded-xl border border-white/5">
                <button 
                    onClick={() => setMode('standard')}
                    className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${mode === 'standard' ? 'bg-indigo-600 text-white shadow-neon-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                    ZWYKŁA
                </button>
                <button 
                    onClick={() => setMode('smart')}
                    className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${mode === 'smart' ? 'bg-fuchsia-600 text-white shadow-neon-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                    INTELIGENTNA (SMART)
                </button>
            </div>

            {/* Name Input */}
            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Nazwa</label>
                <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder={mode === 'standard' ? "Moja Playlista" : "Hity 2024 House"}
                    className="w-full bg-[#0a0a0f] border border-white/10 rounded-xl py-3 px-4 text-white focus:border-cyan-500 focus:outline-none transition-colors"
                    autoFocus
                />
            </div>

            {/* Smart Rules */}
            {mode === 'smart' && (
                <div className="space-y-3">
                    <div className="flex justify-between items-center">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Reguły (pasuje do wszystkich)</label>
                        <button onClick={addRule} className="text-xs text-cyan-400 hover:text-cyan-300 font-bold">+ DODAJ WARUNEK</button>
                    </div>

                    <div className="space-y-2">
                        {rules.map((rule) => (
                            <div key={rule.id} className="flex gap-2 items-center bg-[#0a0a0f] p-2 rounded-lg border border-white/5">
                                <select 
                                    value={rule.field}
                                    onChange={(e) => updateRule(rule.id, { field: e.target.value as SmartPlaylistRuleField })}
