// Camelot Key System mapping
// 1A = Ab Minor, 1B = B Major, etc.
type CamelotKey = string;

interface KeyData {
  camelot: string;
  musical: string;
}

// Simplified map for parsing various key formats to Camelot
const keyMap: Record<string, string> = {
  // Major
  'B': '1B', 'B MAJ': '1B', 'B MAJOR': '1B',
  'F#': '2B', 'F# MAJ': '2B', 'GB': '2B',
  'DB': '3B', 'C#': '3B',
  'AB': '4B', 'G#': '4B',
  'EB': '5B', 'D#': '5B',
  'BB': '6B', 'A#': '6B',
  'F': '7B', 'F MAJ': '7B', 'F MAJOR': '7B',
  'C': '8B', 'C MAJ': '8B', 'C MAJOR': '8B',
  'G': '9B', 'G MAJ': '9B', 'G MAJOR': '9B',
  'D': '10B', 'D MAJ': '10B', 'D MAJOR': '10B',
  'A': '11B', 'A MAJ': '11B', 'A MAJOR': '11B',
  'E': '12B', 'E MAJ': '12B', 'E MAJOR': '12B',

  // Minor
  'ABM': '1A', 'G#M': '1A', 'AB MIN': '1A',
  'EBM': '2A', 'D#M': '2A', 'EB MIN': '2A',
  'BBM': '3A', 'A#M': '3A', 'BB MIN': '3A',
  'FM': '4A', 'F MIN': '4A', 'F MINOR': '4A',
  'CM': '5A', 'C MIN': '5A', 'C MINOR': '5A',
  'GM': '6A', 'G MIN': '6A', 'G MINOR': '6A',
  'DM': '7A', 'D MIN': '7A', 'D MINOR': '7A',
  'AM': '8A', 'A MIN': '8A', 'A MINOR': '8A',
  'EM': '9A', 'E MIN': '9A', 'E MINOR': '9A',
  'BM': '10A', 'B MIN': '10A', 'B MINOR': '10A',
  'F#M': '11A', 'GBM': '11A', 'F# MIN': '11A',
  'DBM': '12A', 'C#M': '12A', 'DB MIN': '12A',
};

export const parseKey = (rawKey: string | undefined): string | null => {
  if (!rawKey) return null;
  const cleanKey = rawKey.trim().toUpperCase();

  // If already in Camelot format (e.g., 8A, 11B)
  if (/^(1[0-2]|[1-9])[AB]$/.test(cleanKey)) {
    return cleanKey;
  }

  // Try to map musical notation
  return keyMap[cleanKey] || null;
};

export interface HarmonicMatch {
  score: number; // 0-100, where 100 is perfect
  type: 'Perfect' | 'Harmonic' | 'Energy Boost' | 'Mood Change' | 'Clash';
  description: string;
  color: string; // Tailwind class or hex
}

export const analyzeTransition = (bpm1: number | undefined, key1: string | undefined, bpm2: number | undefined, key2: string | undefined): HarmonicMatch => {
  let score = 100;
  let type: HarmonicMatch['type'] = 'Perfect';
  let description = 'Idealne połączenie';
  let color = 'text-green-400';

  // 1. BPM Check
  if (bpm1 && bpm2) {
    const diff = Math.abs(bpm1 - bpm2);
    const percentDiff = (diff / bpm1) * 100;

    if (percentDiff > 10) {
      score -= 30;
      description = 'Duża różnica BPM';
    } else if (percentDiff > 5) {
      score -= 10;
    }
  }

  // 2. Key Check
  const cKey1 = parseKey(key1);
  const cKey2 = parseKey(key2);

  if (!cKey1 || !cKey2) {
    return { score: 50, type: 'Harmonic', description: 'Brak danych o tonacji', color: 'text-slate-400' };
  }

  const num1 = parseInt(cKey1.slice(0, -1));
  const letter1 = cKey1.slice(-1);
  const num2 = parseInt(cKey2.slice(0, -1));
  const letter2 = cKey2.slice(-1);

  // Exact Match
  if (cKey1 === cKey2) {
    // Keep perfect score
  } 
  // Relative Major/Minor (8A <-> 8B)
  else if (num1 === num2 && letter1 !== letter2) {
    type = 'Mood Change';
    description = 'Zmiana nastroju (Względna)';
    color = 'text-cyan-400';
  }
  // Harmonic (+/- 1 number, same letter) - e.g. 8A -> 9A or 8A -> 7A
  else if (letter1 === letter2 && (Math.abs(num1 - num2) === 1 || Math.abs(num1 - num2) === 11)) {
    type = 'Harmonic';
    description = 'Harmoniczne przejście';
    color = 'text-green-400';
  }
  // Energy Boost (+1 semitone / +7 Camelot steps or +2 numbers)
  // Simple Energy Boost rule in Camelot: +1 number (often works well) or +2 numbers
  else if (letter1 === letter2 && ((num2 - num1 === 2) || (num1 === 11 && num2 === 1) || (num1 === 12 && num2 === 2))) {
    type = 'Energy Boost';
    description = 'Podbicie energii (+2)';
    color = 'text-fuchsia-400';
  }
  else {
    score -= 60;
    type = 'Clash';
    description = 'Dysharmonia';
    color = 'text-red-500';
  }

  return { score: Math.max(0, score), type, description, color };
};
