interface MixPlannerTabProps {
  files: AudioFile[];
  playingFileId: string | null;
  onPlayPause: (fileId: string) => void;
}

const MixPlannerTab: React.FC<MixPlannerTabProps> = ({ files, playingFileId, onPlayPause }) => {
  const [playlist, setPlaylist] = useState<AudioFile[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Filter available tracks (exclude ones already in playlist for cleaner UI, or keep them)
  const availableTracks = useMemo(() => {
    return files.filter(f => 
      (f.originalTags.title || f.file.name).toLowerCase().includes(searchQuery.toLowerCase()) ||
      (f.originalTags.artist || '').toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [files, searchQuery]);

  const addToPlaylist = (file: AudioFile) => {
    setPlaylist([...playlist, file]);
  };

  const removeFromPlaylist = (index: number) => {
    const newPlaylist = [...playlist];
    newPlaylist.splice(index, 1);
    setPlaylist(newPlaylist);
  };

  const moveItem = (index: number, direction: 'up' | 'down') => {
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === playlist.length - 1) return;

    const newPlaylist = [...playlist];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    const temp = newPlaylist[index];
    newPlaylist[index] = newPlaylist[targetIndex];
    newPlaylist[targetIndex] = temp;
    setPlaylist(newPlaylist);
  };

  // --- Sub-components ---

  const TrackCard = ({ file, onClick, actionIcon }: { file: AudioFile, onClick: () => void, actionIcon: React.ReactNode }) => {
      const tags = file.fetchedTags || file.originalTags;
      const isPlaying = playingFileId === file.id;

      return (
          <div className="flex items-center gap-3 p-3 bg-[#1a1a2e] border border-white/5 rounded-xl hover:bg-white/5 transition-colors group">
              <div className="relative w-10 h-10 flex-shrink-0 cursor-pointer" onClick={() => onPlayPause(file.id)}>
                  <AlbumCover tags={tags} className="w-full h-full rounded-md" />
                  <div className={`absolute inset-0 flex items-center justify-center bg-black/50 rounded-md transition-opacity ${isPlaying ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                      {isPlaying ? (
                          <div className="flex gap-[2px] items-end h-3">
                              <div className="w-1 bg-cyan-400 h-full animate-music-bar"></div>
                              <div className="w-1 bg-cyan-400 h-2/3 animate-music-bar" style={{animationDelay:'0.1s'}}></div>
                          </div>
                      ) : (
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                      )}
                  </div>
              </div>
              <div className="flex-1 min-w-0">
                  <div className="text-sm font-bold text-white truncate">{tags.title || file.file.name}</div>
                  <div className="text-xs text-slate-400 truncate">{tags.artist || 'Unknown'}</div>
              </div>
              <div className="text-right mr-2">
                  <div className="text-xs font-mono text-cyan-400 font-bold">{tags.bpm || '-'}</div>
                  <div className="text-xs font-mono text-fuchsia-400 font-bold">{tags.initialKey || '-'}</div>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); onClick(); }}
                className="p-2 rounded-lg bg-white/5 hover:bg-white/10 text-slate-300 hover:text-white transition-colors"
              >
                  {actionIcon}
              </button>
          </div>
      );
  };

  const TransitionConnector = ({ prev, next }: { prev: AudioFile, next: AudioFile }) => {
      const tags1 = prev.fetchedTags || prev.originalTags;
      const tags2 = next.fetchedTags || next.originalTags;
      const analysis = analyzeTransition(tags1.bpm, tags1.initialKey, tags2.bpm, tags2.initialKey);

      const bpmDiff = tags1.bpm && tags2.bpm ? Math.round(tags2.bpm - tags1.bpm) : '?';
      const bpmDiffStr = bpmDiff > 0 ? `+${bpmDiff}` : `${bpmDiff}`;

      return (
          <div className="flex items-center justify-center py-2 relative">
              <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-white/5 -z-10"></div>

