                    className="w-full bg-[#050505] border border-white/10 rounded-lg py-2 px-3 text-sm text-white focus:border-indigo-500 outline-none"
                />
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
                {availableTracks.map(file => (
                    <TrackCard 
                        key={file.id} 
                        file={file} 
                        onClick={() => addToPlaylist(file)}
                        actionIcon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>}
                    />
                ))}
            </div>
        </div>

        {/* Right Column: Timeline */}
        <div className="flex-1 flex flex-col relative bg-gradient-to-b from-[#0f0f16] to-[#050505]">
            <div className="p-4 border-b border-white/5 flex justify-between items-center bg-[#0a0a0f]/80 backdrop-blur-md sticky top-0 z-20">
                <div>
                    <h2 className="text-xl font-bold text-white neon-text-blue">Mix Planner</h2>
                    <p className="text-xs text-slate-500">
                        {playlist.length} utworów • Szacowany czas: {playlist.length * 3} min
                    </p>
                </div>
                <button 
                    onClick={() => setPlaylist([])}
                    className="text-xs font-bold text-red-400 hover:text-red-300 uppercase tracking-wider px-3 py-1 rounded hover:bg-white/5 transition-colors"
                >
                    Wyczyść
                </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 custom-scrollbar relative">
                {playlist.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-50 border-2 border-dashed border-slate-800 rounded-2xl m-4">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" /></svg>
                        <p>Dodaj utwory z puli po lewej, aby zacząć planować set.</p>
