// Camelot Key System mapping
// 1A = Ab Minor, 1B = B Major, etc.
type CamelotKey = string;

interface KeyData {
  camelot: string;
  musical: string;
}

// Simplified map for parsing various key formats to Camelot
const keyMap: Record<string, string> = {
  // Major
  'B': '1B', 'B MAJ': '1B', 'B MAJOR': '1B',
  'F#': '2B', 'F# MAJ': '2B', 'GB': '2B',
  'DB': '3B', 'C#': '3B',
  'AB': '4B', 'G#': '4B',
  'EB': '5B', 'D#': '5B',
  'BB': '6B', 'A#': '6B',
  'F': '7B', 'F MAJ': '7B', 'F MAJOR': '7B',
  'C': '8B', 'C MAJ': '8B', 'C MAJOR': '8B',
  'G': '9B', 'G MAJ': '9B', 'G MAJOR': '9B',
  'D': '10B', 'D MAJ': '10B', 'D MAJOR': '10B',
  'A': '11B', 'A MAJ': '11B', 'A MAJOR': '11B',
  'E': '12B', 'E MAJ': '12B', 'E MAJOR': '12B',

  // Minor
  'ABM': '1A', 'G#M': '1A', 'AB MIN': '1A',
  'EBM': '2A', 'D#M': '2A', 'EB MIN': '2A',
  'BBM': '3A', 'A#M': '3A', 'BB MIN': '3A',
  'FM': '4A', 'F MIN': '4A', 'F MINOR': '4A',
