  'EM': '9A', 'E MIN': '9A', 'E MINOR': '9A',
  'BM': '10A', 'B MIN': '10A', 'B MINOR': '10A',
  'F#M': '11A', 'GBM': '11A', 'F# MIN': '11A',
  'DBM': '12A', 'C#M': '12A', 'DB MIN': '12A',
};

export const parseKey = (rawKey: string | undefined): string | null => {
  if (!rawKey) return null;
  const cleanKey = rawKey.trim().toUpperCase();

  // If already in Camelot format (e.g., 8A, 11B)
  if (/^(1[0-2]|[1-9])[AB]$/.test(cleanKey)) {
    return cleanKey;
  }

  // Try to map musical notation
  return keyMap[cleanKey] || null;
};

