<content><![CDATA[
import React, { useState, useMemo } from 'react';
import { DragDropContext, Droppable, Draggable, DropResult } from 'react-beautiful-dnd';
import { AudioFile } from '../types';
import AlbumCover from './AlbumCover';
import { analyzeTransition } from '../utils/harmonicUtils';

// Workaround for React 18 Strict Mode with react-beautiful-dnd
import { useEffect } from 'react';
export const StrictModeDroppable = ({ children, ...props }: any) => {
  const [enabled, setEnabled] = useState(false);
  useEffect(() => {
    const animation = requestAnimationFrame(() => setEnabled(true));
    return () => {
      cancelAnimationFrame(animation);
      setEnabled(false);
    };
  }, []);
  if (!enabled) return null;
  return <Droppable {...props}>{children}</Droppable>;
};

interface MixPlannerTabProps {
  files: AudioFile[];
  playingFileId: string | null;
  onPlayPause: (fileId: string) => void;
  onSaveAsPlaylist: (name: string, trackIds: string[]) => void;
}

const MixPlannerTab: React.FC<MixPlannerTabProps> = ({ files, playingFileId, onPlayPause, onSaveAsPlaylist }) => {
  const [playlist, setPlaylist] = useState<AudioFile[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [mixName, setMixName] = useState('My Awesome Set');

  // Filter available tracks (exclude ones already in playlist)
  const availableTracks = useMemo(() => {
    const playlistIds = new Set(playlist.map(p => p.id));
    return files.filter(f => 
      !playlistIds.has(f.id) &&
      ((f.originalTags.title || f.file.name).toLowerCase().includes(searchQuery.toLowerCase()) ||
      (f.originalTags.artist || '').toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [files, searchQuery, playlist]);

  const addToPlaylist = (file: AudioFile) => {
    setPlaylist([...playlist, file]);
  };

  const removeFromPlaylist = (index: number) => {
    const newPlaylist = [...playlist];
    newPlaylist.splice(index, 1);
    setPlaylist(newPlaylist);
  };

  const onDragEnd = (result: DropResult) => {
    if (!result.destination) return;

    const newPlaylist = Array.from(playlist);
    const [reorderedItem] = newPlaylist.splice(result.source.index, 1);
    newPlaylist.splice(result.destination.index, 0, reorderedItem);

    setPlaylist(newPlaylist);
  };

  const handleSave = () => {
      if (playlist.length === 0) return;
      onSaveAsPlaylist(mixName, playlist.map(f => f.id));
      alert(`Zapisano "${mixName}" jako nową playlistę!`);
  };

  // --- Visual Components ---

  const TrackCard = ({ file, onClick, actionIcon, isDragging }: { file: AudioFile, onClick: () => void, actionIcon: React.ReactNode, isDragging?: boolean }) => {
      const tags = file.fetchedTags || file.originalTags;
      const isPlaying = playingFileId === file.id;

      const cardClasses = `flex items-center gap-3 p-3 bg-[#1a1a2e] border transition-all group relative
        ${isDragging 
            ? 'border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.3)] scale-105 z-50 rounded-xl' 
            : 'border-white/5 hover:bg-white/5 rounded-xl'}`;

      return (
          <div className={cardClasses}>
              <div className="relative w-10 h-10 flex-shrink-0 cursor-pointer" onClick={() => onPlayPause(file.id)}>
                  <AlbumCover tags={tags} className="w-full h-full rounded-md" />
                  <div className={`absolute inset-0 flex items-center justify-center bg-black/50 rounded-md transition-opacity ${isPlaying ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                      {isPlaying ? (
                          <div className="flex gap-[2px] items-end h-3">
                              <div className="w-1 bg-cyan-400 h-full animate-music-bar"></div>
                              <div className="w-1 bg-cyan-400 h-2/3 animate-music-bar" style={{animationDelay:'0.1s'}}></div>
                          </div>
                      ) : (
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                      )}
                  </div>
              </div>
              <div className="flex-1 min-w-0">
                  <div className="text-sm font-bold text-white truncate">{tags.title || file.file.name}</div>
                  <div className="text-xs text-slate-400 truncate">{tags.artist || 'Unknown'}</div>
              </div>
              <div className="text-right mr-2">
                  <div className="text-xs font-mono text-cyan-400 font-bold">{tags.bpm || '-'}</div>
                  <div className="text-xs font-mono text-fuchsia-400 font-bold">{tags.initialKey || '-'}</div>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); onClick(); }}
                className="p-2 rounded-lg bg-white/5 hover:bg-white/10 text-slate-300 hover:text-white transition-colors"
              >
                  {actionIcon}
              </button>
          </div>
      );
  };

  const TransitionConnector = ({ prev, next }: { prev: AudioFile, next: AudioFile }) => {
      const tags1 = prev.fetchedTags || prev.originalTags;
      const tags2 = next.fetchedTags || next.originalTags;
      const analysis = analyzeTransition(tags1.bpm, tags1.initialKey, tags2.bpm, tags2.initialKey);

      const bpmDiff = tags1.bpm && tags2.bpm ? Math.round(tags2.bpm - tags1.bpm) : '?';
      const bpmDiffStr = bpmDiff > 0 ? `+${bpmDiff}` : `${bpmDiff}`;

      return (
          <div className="flex items-center justify-center py-2 relative">
              <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-white/5 -z-10"></div>

              <div className={`bg-[#050505] border border-white/10 px-3 py-1 rounded-full flex items-center gap-3 text-xs shadow-lg transform transition-transform hover:scale-105 z-10 ${analysis.color}`}>
                  <div className={`w-2 h-2 rounded-full ${analysis.bgColor.replace('/20', '')}`}></div>
                  <div className="font-bold">
                      {analysis.type} <span className="opacity-70 text-[10px]">({analysis.score}%)</span>
                  </div>
                  {bpmDiff !== '?' && Math.abs(Number(bpmDiff)) > 0 && (
                      <>
                        <div className="h-3 w-px bg-white/10"></div>
                        <div className="text-slate-400 font-mono">
                            BPM: <span className={Math.abs(Number(bpmDiff)) > 5 ? 'text-red-400' : 'text-slate-200'}>{bpmDiffStr}</span>
                        </div>
                      </>
                  )}
              </div>
          </div>
      );
  };

  const EnergyGraph = () => {
      if (playlist.length < 2) return null;

      const maxBpm = Math.max(...playlist.map(f => (f.fetchedTags?.bpm || f.originalTags.bpm || 120))) + 10;
      const minBpm = Math.min(...playlist.map(f => (f.fetchedTags?.bpm || f.originalTags.bpm || 120))) - 10;

      return (
          <div className="h-16 w-full flex items-end gap-1 px-4 mb-4 opacity-50 hover:opacity-100 transition-opacity">
              {playlist.map((f, i) => {
                  const bpm = f.fetchedTags?.bpm || f.originalTags.bpm || 120;
                  const height = ((bpm - minBpm) / (maxBpm - minBpm)) * 100;
                  return (
                      <div key={i} className="flex-1 flex flex-col justify-end group/bar relative">
                          <div 
                            className="bg-gradient-to-t from-indigo-900 to-cyan-500 rounded-t-sm w-full transition-all duration-500"
                            style={{ height: `${Math.max(10, height)}%` }}
                          ></div>
                          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-1 text-[9px] bg-black px-1 rounded text-white opacity-0 group-hover/bar:opacity-100 pointer-events-none">
                              {bpm}
                          </div>
                      </div>
                  )
              })}
          </div>
      )
  }

  return (
    <div className="flex h-full bg-[#050505] text-slate-200 overflow-hidden animate-fade-in">
        {/* Left Column: Track Pool */}
        <div className="w-1/3 min-w-[300px] border-r border-white/5 flex flex-col bg-[#0a0a0f]">
            <div className="p-4 border-b border-white/5 bg-white/5">
                <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-3">Pula Utworów</h2>
                <div className="relative">
                    <input 
                        type="text" 
                        placeholder="Szukaj w bibliotece..." 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full bg-[#050505] border border-white/10 rounded-lg py-2 pl-9 pr-3 text-sm text-white focus:border-indigo-500 outline-none placeholder:text-slate-600"
                    />
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-3 top-2.5 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
                {availableTracks.length === 0 ? (
                    <div className="text-center p-4 text-slate-500 text-xs">
                        {files.length === 0 ? "Brak plików w bibliotece." : "Brak wyników lub wszystkie dodane."}
                    </div>
                ) : (
                    availableTracks.map(file => (
                        <TrackCard 
                            key={file.id} 
                            file={file} 
                            onClick={() => addToPlaylist(file)}
                            actionIcon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-green-400" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>}
                        />
                    ))
                )}
            </div>
        </div>

        {/* Right Column: Timeline / DnD Area */}
        <div className="flex-1 flex flex-col relative bg-gradient-to-b from-[#0f0f16] to-[#050505]">
            {/* Header */}
            <div className="p-4 border-b border-white/5 flex justify-between items-center bg-[#0a0a0f]/80 backdrop-blur-md sticky top-0 z-20 shadow-neon-sm">
                <div className="flex items-center gap-4">
                    <input 
                        type="text" 
                        value={mixName}
                        onChange={(e) => setMixName(e.target.value)}
                        className="text-xl font-bold text-white bg-transparent border-b border-transparent hover:border-white/20 focus:border-cyan-500 outline-none transition-colors w-64"
                    />
                    <div className="text-xs text-slate-500 flex gap-2">
                        <span>{playlist.length} tracków</span>
                        <span>•</span>
                        <span>~{Math.round(playlist.length * 3.5)} min</span>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={() => setPlaylist([])}
                        className="text-xs font-bold text-slate-500 hover:text-red-400 uppercase tracking-wider px-3 py-2 rounded hover:bg-white/5 transition-colors"
                    >
                        Wyczyść
                    </button>
                    <button 
                        onClick={handleSave}
                        disabled={playlist.length === 0}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-600 text-white text-xs font-bold rounded-lg shadow-lg transition-all"
                    >
                        ZAPISZ JAKO PLAYLISTĘ
                    </button>
                </div>
            </div>

            {/* Energy Visualization */}
            <div className="border-b border-white/5 bg-[#0a0a0f]/50">
                <EnergyGraph />
            </div>

            {/* Timeline */}
            <div className="flex-1 overflow-y-auto p-6 custom-scrollbar relative">
                <DragDropContext onDragEnd={onDragEnd}>
                    <StrictModeDroppable droppableId="mix-timeline">
                        {(provided: any) => (
                            <div 
                                {...provided.droppableProps} 
                                ref={provided.innerRef}
                                className="space-y-0 max-w-3xl mx-auto pb-32"
                            >
                                {playlist.length === 0 ? (
                                    <div className="h-64 flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
                                        <p className="text-lg font-bold mb-2">Twój Timeline jest pusty</p>
                                        <p className="text-sm">Przeciągnij utwory z puli lub kliknij "+", aby zacząć.</p>
                                    </div>
                                ) : (
                                    playlist.map((file, index) => (
                                        <React.Fragment key={file.id}>
                                            {/* Transition Connector */}
                                            {index > 0 && (
                                                <TransitionConnector prev={playlist[index - 1]} next={file} />
                                            )}

                                            <Draggable draggableId={file.id} index={index}>
                                                {(provided, snapshot) => (
                                                    <div
                                                        ref={provided.innerRef}
                                                        {...provided.draggableProps}
                                                        {...provided.dragHandleProps}
                                                        className="flex items-center gap-4 group my-1"
                                                    >
                                                        {/* Number & Handle */}
                                                        <div className="text-2xl font-bold text-slate-800 w-8 text-center select-none group-hover:text-slate-600">
                                                            {index + 1}
                                                        </div>

                                                        <div className="flex-1">
                                                            <TrackCard 
                                                                file={file} 
                                                                onClick={() => removeFromPlaylist(index)}
                                                                actionIcon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-400" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>}
                                                                isDragging={snapshot.isDragging}
                                                            />
                                                        </div>

                                                        {/* Drag Handle Icon (Visual only) */}
                                                        <div className="text-slate-700">
                                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" /></svg>
                                                        </div>
                                                    </div>
                                                )}
                                            </Draggable>
                                        </React.Fragment>
                                    ))
                                )}
                                {provided.placeholder}
                            </div>
                        )}
                    </StrictModeDroppable>
                </DragDropContext>
            </div>
        </div>
    </div>
  );
};

export default MixPlannerTab;
]]></content>
