import React, { useMemo, useState } from 'react';
import { AudioFile } from '../types';
import AlbumCover from './AlbumCover';
import { analyzeTransition } from '../utils/harmonicUtils';

interface LiveDJTabProps {
  files: AudioFile[];
  playingFileId: string | null;
  onPlayPause: (fileId: string) => void;
  isPlaying: boolean;
}

const LiveDJTab: React.FC<LiveDJTabProps> = ({ files, playingFileId, onPlayPause, isPlaying }) => {
  const [deckBFileId, setDeckBFileId] = useState<string | null>(null);

  // Deck A is always the currently playing global track
  const deckAFile = useMemo(() => files.find(f => f.id === playingFileId) || null, [files, playingFileId]);
  const deckBFile = useMemo(() => files.find(f => f.id === deckBFileId) || null, [files, deckBFileId]);

  // AI Suggestions Logic
  const suggestions = useMemo(() => {
      if (!deckAFile) return [];

      const tagsA = deckAFile.fetchedTags || deckAFile.originalTags;

      const scored = files
        .filter(f => f.id !== deckAFile.id && f.id !== deckBFileId) // Don't suggest current or loaded
        .map(f => {
            const tagsB = f.fetchedTags || f.originalTags;
            const analysis = analyzeTransition(tagsA.bpm, tagsA.initialKey, tagsB.bpm, tagsB.initialKey);
            return { file: f, analysis };
        })
        .filter(item => item.analysis.score > 60) // Only good matches
        .sort((a, b) => b.analysis.score - a.analysis.score)
        .slice(0, 4); // Top 4

      return scored;
  }, [deckAFile, deckBFileId, files]);

  // --- Sub-components ---

  const Deck = ({ id, label, file, isMain, isPlayingNow }: { id: string, label: string, file: AudioFile | null, isMain: boolean, isPlayingNow: boolean }) => {
      const tags = file?.fetchedTags || file?.originalTags;

      return (
          <div className="flex-1 bg-[#1a1a2e] rounded-2xl border border-white/5 p-6 flex flex-col items-center relative overflow-hidden shadow-neon-md">
              {/* Background Glow */}
              <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 rounded-full blur-[100px] opacity-20 pointer-events-none ${isMain ? 'bg-cyan-500' : 'bg-fuchsia-500'}`}></div>

              <div className="w-full flex justify-between items-center mb-6 z-10">
                  <div className={`text-xl font-bold uppercase tracking-widest ${isMain ? 'text-cyan-400' : 'text-fuchsia-400'}`}>{label}</div>
                  <div className="flex gap-2">
                      <div className="bg-[#0a0a0f] px-3 py-1 rounded text-xs font-mono text-slate-400 border border-white/10">
                          BPM <span className="text-white font-bold">{tags?.bpm || '---'}</span>
                      </div>
                      <div className="bg-[#0a0a0f] px-3 py-1 rounded text-xs font-mono text-slate-400 border border-white/10">
                          KEY <span className="text-white font-bold">{tags?.initialKey || '--'}</span>
                      </div>
                  </div>
              </div>

              {/* Vinyl / Cover */}
              <div className="relative w-64 h-64 mb-8 z-10 group">
                  {/* Vinyl Ring */}
                  <div className="absolute inset-0 rounded-full border-[8px] border-[#0a0a0f] shadow-2xl bg-[#111]"></div>
                  {/* Rotating Inner */}
                  <div className={`absolute inset-2 rounded-full overflow-hidden ${isPlayingNow ? 'animate-spin-slow' : ''} transition-all duration-1000`}>
                      <AlbumCover tags={tags} className="w-full h-full object-cover opacity-80" />
                      {/* Center Hole */}
                      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-16 h-16 bg-[#0a0a0f] rounded-full border-4 border-white/10 flex items-center justify-center">
                          <div className={`w-2 h-2 rounded-full ${isMain ? 'bg-cyan-500' : 'bg-fuchsia-500'}`}></div>
                      </div>
                  </div>
              </div>

              {/* Info */}
              <div className="text-center w-full z-10 mb-6">
                  <h3 className="text-lg font-bold text-white truncate px-4">{tags?.title || (file ? file.file.name : 'No Track Loaded')}</h3>
                  <p className="text-slate-400 text-sm truncate">{tags?.artist || '---'}</p>
              </div>

              {/* Controls */}
              <div className="w-full flex justify-center gap-4 z-10 mt-auto">
                  <button className="w-16 h-16 rounded-full bg-[#0a0a0f] border border-white/10 flex items-center justify-center text-slate-400 hover:text-white hover:border-white/30 transition-all active:scale-95 shadow-lg">
                      CUE
                  </button>
                  <button 
                    onClick={() => file && onPlayPause(file.id)}
                    className={`w-16 h-16 rounded-full flex items-center justify-center text-white transition-all active:scale-95 shadow-lg ${isPlayingNow ? 'bg-green-500 hover:bg-green-400 shadow-[0_0_20px_rgba(34,197,94,0.4)]' : 'bg-white/10 hover:bg-white/20'}`}
                  >
