        {/* Decks Area */}
        <div className="flex-1 flex p-4 gap-4 overflow-hidden relative">
            <Deck id="A" label="DECK A" file={deckAFile} isMain={true} isPlayingNow={isPlaying && deckAFile?.id === playingFileId} />

            {/* Central Info / AI Suggestions */}
