                    <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-green-400" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" /></svg>
                        AI SUGGESTIONS
                    </h3>

                    {deckAFile ? (
                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
                            {suggestions.map(({ file, analysis }) => (
                                <div 
                                    key={file.id} 
                                    onClick={() => setDeckBFileId(file.id)}
                                    className="p-2 rounded-lg bg-white/5 hover:bg-white/10 cursor-pointer transition-colors border border-transparent hover:border-white/20 group"
