/**
 * Prosty algorytm detekcji BPM działający w przeglądarce.
 * Analizuje piki energii w sygnale audio.
 */

export const detectBPM = async (file: File): Promise<number> => {
  return new Promise(async (resolve, reject) => {
    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();

      // Wczytaj tylko fragment pliku (np. pierwsze 30 sekund lub środek), aby oszczędzić pamięć,
      // ale dla precyzji lepiej wczytać całość lub reprezentatywny fragment.
      // Tutaj wczytujemy całość jako ArrayBuffer.
      const arrayBuffer = await file.arrayBuffer();

      // Dekodowanie (to może chwilę potrwać dla dużych plików)
      const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);

      // Przygotowanie danych (offline processing)
      const offlineContext = new OfflineAudioContext(1, audioBuffer.length, audioBuffer.sampleRate);
      const source = offlineContext.createBufferSource();
      source.buffer = audioBuffer;

      // Filtr dolnoprzepustowy, aby skupić się na basie (kick drum)
      const filter = offlineContext.createBiquadFilter();
      filter.type = "lowpass";
      filter.frequency.value = 150;
      source.connect(filter);
      filter.connect(offlineContext.destination);
      source.start(0);

      const renderedBuffer = await offlineContext.startRendering();
      const data = renderedBuffer.getChannelData(0);

      // Analiza pików (Peak Detection)
      const peaks = getPeaks([data]);

      // Liczenie interwałów między pikami
      const groups = getIntervals(peaks);

      // Wybór najczęstszego tempa
      const top = groups.sort((a, b) => b.count - a.count).slice(0, 5);

      if (top.length === 0) {
          resolve(0);
          return;
      }

      // Średnia ważona z najlepszych wyników
      let bpm = Math.round(top[0].tempo);

      resolve(bpm);

    } catch (e) {
      console.error("BPM Detection Error:", e);
      reject(e);
    }
  });
};

// Pomocnicze funkcje do algorytmu
function getPeaks(data: Float32Array[]) {
  const partSize = 22050; // ~0.5s przy 44.1kHz
  const parts = data[0].length / partSize;
  let peaks = [];

  for (let i = 0; i < parts; i++) {
    let max = 0;
    for (let j = i * partSize; j < (i + 1) * partSize; j++) {
      const vol = Math.abs(data[0][j]);
      if (!max || (vol > max)) max = vol;
    }
    peaks.push({ volume: max, position: i });
  }

  // Sortuj po głośności i weź najgłośniejsze
  peaks.sort((a, b) => b.volume - a.volume);
  peaks = peaks.splice(0, peaks.length * 0.5); // Top 50% peaks
  peaks.sort((a, b) => a.position - b.position); // Przywróć kolejność czasową

  return peaks;
}

function getIntervals(peaks: any[]) {
  const groups: { tempo: number, count: number }[] = [];

  peaks.forEach((peak, index) => {
    for (let i = 1; (index + i) < peaks.length && i < 10; i++) {
      const group = {
        tempo: (60 * 44100) / (22050 * (peaks[index + i].position - peak.position)), // Przybliżone BPM
        count: 1
      };

      while (group.tempo < 90) group.tempo *= 2;
      while (group.tempo > 180) group.tempo /= 2;

      group.tempo = Math.round(group.tempo);

      if (!(group.tempo > 90 && group.tempo < 180)) continue;

      const found = groups.some(interval => {
        if (interval.tempo === group.tempo) {
          interval.count++;
          return true;
        }
        return false;
      });
      if (!found) groups.push(group);
    }
  });
  return groups;
}
