<content><![CDATA[
import React, { useMemo, useState } from 'react';
import { AudioFile } from '../types';
import AlbumCover from './AlbumCover';
import { analyzeTransition } from '../utils/harmonicUtils';

interface LiveDJTabProps {
  files: AudioFile[];
  playingFileId: string | null;
  onPlayPause: (fileId: string) => void;
  isPlaying: boolean;
}

const LiveDJTab: React.FC<LiveDJTabProps> = ({ files, playingFileId, onPlayPause, isPlaying }) => {
  const [deckBFileId, setDeckBFileId] = useState<string | null>(null);

  // Deck A is always the currently playing global track
  const deckAFile = useMemo(() => files.find(f => f.id === playingFileId) || null, [files, playingFileId]);
  const deckBFile = useMemo(() => files.find(f => f.id === deckBFileId) || null, [files, deckBFileId]);

  // AI Suggestions Logic
  const suggestions = useMemo(() => {
      if (!deckAFile) return [];

      const tagsA = deckAFile.fetchedTags || deckAFile.originalTags;

      const scored = files
        .filter(f => f.id !== deckAFile.id && f.id !== deckBFileId) // Don't suggest current or loaded
        .map(f => {
            const tagsB = f.fetchedTags || f.originalTags;
            const analysis = analyzeTransition(tagsA.bpm, tagsA.initialKey, tagsB.bpm, tagsB.initialKey);
            return { file: f, analysis };
        })
        .filter(item => item.analysis.score > 60) // Only good matches
        .sort((a, b) => b.analysis.score - a.analysis.score)
        .slice(0, 4); // Top 4

      return scored;
  }, [deckAFile, deckBFileId, files]);

  // --- Sub-components ---

  const PitchFader = ({ isMain }: { isMain: boolean }) => (
      <div className="h-64 w-8 bg-[#0a0a0f] rounded-full border border-white/10 relative flex justify-center py-2 mx-4 shadow-inner">
          <div className="w-[1px] h-full bg-white/10 absolute"></div>
          <div className="w-[8px] h-[1px] bg-white/30 absolute top-1/2"></div>
          {/* Knob */}
          <div className={`w-6 h-10 rounded shadow-lg border absolute top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing ${isMain ? 'bg-cyan-500 border-cyan-300' : 'bg-fuchsia-500 border-fuchsia-300'}`}>
              <div className="w-full h-[1px] bg-white absolute top-1/2 -translate-y-1/2"></div>
          </div>
          <span className="absolute -bottom-6 text-[10px] font-mono text-slate-500">PITCH</span>
      </div>
  );

  const Deck = ({ id, label, file, isMain, isPlayingNow }: { id: string, label: string, file: AudioFile | null, isMain: boolean, isPlayingNow: boolean }) => {
      const tags = file?.fetchedTags || file?.originalTags;

      return (
          <div className="flex-1 bg-[#1a1a2e] rounded-2xl border border-white/5 p-4 flex flex-col items-center relative overflow-hidden shadow-neon-md">
              {/* Background Glow */}
              <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 rounded-full blur-[100px] opacity-20 pointer-events-none ${isMain ? 'bg-cyan-500' : 'bg-fuchsia-500'}`}></div>

              {/* Top Bar */}
              <div className="w-full flex justify-between items-center mb-4 z-10 px-2">
                  <div className={`text-xl font-bold uppercase tracking-widest ${isMain ? 'text-cyan-400' : 'text-fuchsia-400'}`}>{label}</div>
                  <div className="flex gap-2">
                      <div className="bg-[#0a0a0f] px-3 py-1 rounded text-xs font-mono text-slate-400 border border-white/10 flex flex-col items-center min-w-[60px]">
                          <span className="text-[9px] opacity-50">BPM</span>
                          <span className="text-white font-bold text-sm">{tags?.bpm || '---'}</span>
                      </div>
                      <div className="bg-[#0a0a0f] px-3 py-1 rounded text-xs font-mono text-slate-400 border border-white/10 flex flex-col items-center min-w-[60px]">
                          <span className="text-[9px] opacity-50">KEY</span>
                          <span className="text-white font-bold text-sm">{tags?.initialKey || '--'}</span>
                      </div>
                  </div>
              </div>

              <div className="flex w-full items-center justify-center flex-grow">
                  {/* Left Side: Controls */}
                  <div className="flex flex-col gap-4 z-10 mr-6">
                      <button className={`w-12 h-8 rounded border border-white/10 text-[10px] font-bold tracking-wider hover:bg-white/10 transition-colors ${isMain ? 'text-cyan-400' : 'text-fuchsia-400'}`}>
                          SYNC
                      </button>
                      <button className="w-12 h-8 rounded border border-white/10 text-[10px] font-bold tracking-wider text-slate-400 hover:bg-white/10 transition-colors">
                          CUE
                      </button>
                  </div>

                  {/* Vinyl */}
                  <div className="relative w-56 h-56 z-10 group">
                      <div className="absolute inset-0 rounded-full border-[6px] border-[#0a0a0f] shadow-2xl bg-[#111]"></div>
                      <div className={`absolute inset-2 rounded-full overflow-hidden ${isPlayingNow ? 'animate-spin-slow' : ''} transition-all duration-1000`}>
                          <AlbumCover tags={tags} className="w-full h-full object-cover opacity-80" />
                          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-14 h-14 bg-[#0a0a0f] rounded-full border-4 border-white/10 flex items-center justify-center">
                              <div className={`w-2 h-2 rounded-full ${isMain ? 'bg-cyan-500' : 'bg-fuchsia-500'}`}></div>
                          </div>
                      </div>
                  </div>

                  {/* Right Side: Pitch */}
                  <PitchFader isMain={isMain} />
              </div>

              {/* Info */}
              <div className="text-center w-full z-10 mb-4 mt-4">
                  <h3 className="text-lg font-bold text-white truncate px-4">{tags?.title || (file ? file.file.name : 'No Track Loaded')}</h3>
                  <p className="text-slate-400 text-sm truncate">{tags?.artist || '---'}</p>
              </div>

              {/* Play Button */}
              <div className="w-full flex justify-center z-10">
                  <button 
                    onClick={() => file && onPlayPause(file.id)}
                    className={`w-16 h-16 rounded-full flex items-center justify-center text-white transition-all active:scale-95 shadow-lg border-4 border-[#0a0a0f] ${isPlayingNow ? 'bg-green-500 hover:bg-green-400 shadow-[0_0_30px_rgba(34,197,94,0.4)]' : 'bg-white/10 hover:bg-white/20'}`}
                  >
                      {isPlayingNow ? (
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                      ) : (
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 pl-1" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                      )}
                  </button>
              </div>
          </div>
      )
  }

  const Mixer = () => (
      <div className="w-full h-32 bg-[#0a0a0f] border-t border-white/5 mt-auto flex items-center justify-center gap-10 relative px-10 shadow-[0_-10px_40px_rgba(0,0,0,0.5)] z-20">
          {/* Fake Visualizer Middle */}
          <div className="absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-cyan-500 via-white to-fuchsia-500 opacity-50"></div>

          <div className="flex flex-col items-center gap-2">
              <div className="h-20 w-2 bg-slate-800 rounded-full relative group cursor-pointer">
                  <div className="absolute bottom-1/2 left-1/2 -translate-x-1/2 w-6 h-4 bg-slate-500 rounded shadow-lg group-hover:bg-white transition-colors"></div>
              </div>
              <span className="text-[10px] text-slate-500 font-bold">VOL A</span>
          </div>

          <div className="flex-1 flex flex-col items-center max-w-lg">
              <div className="w-full h-3 bg-[#111] border border-white/10 rounded-full relative flex items-center px-1">
                  {/* Crossfader Knob */}
                  <div className="w-12 h-8 bg-gradient-to-b from-slate-200 to-slate-400 rounded shadow-[0_0_15px_rgba(255,255,255,0.2)] absolute left-1/2 -translate-x-1/2 cursor-grab active:cursor-grabbing border border-black/50">
                      <div className="w-[1px] h-full bg-black/50 mx-auto"></div>
                  </div>
              </div>
              <span className="text-[10px] text-slate-500 font-bold mt-3 tracking-widest">CROSSFADER</span>
          </div>

          <div className="flex flex-col items-center gap-2">
              <div className="h-20 w-2 bg-slate-800 rounded-full relative group cursor-pointer">
                  <div className="absolute bottom-1/2 left-1/2 -translate-x-1/2 w-6 h-4 bg-slate-500 rounded shadow-lg group-hover:bg-white transition-colors"></div>
              </div>
              <span className="text-[10px] text-slate-500 font-bold">VOL B</span>
          </div>
      </div>
  )

  return (
    <div className="flex flex-col h-full bg-[#050505] animate-fade-in overflow-hidden relative">
        {/* Decks Area */}
        <div className="flex-1 flex p-4 gap-4 overflow-hidden relative pb-32">
            <Deck id="A" label="DECK A" file={deckAFile} isMain={true} isPlayingNow={isPlaying && deckAFile?.id === playingFileId} />

            {/* Central Info / AI Suggestions - Absolute centered to float above */}
            <div className="absolute top-4 bottom-32 left-1/2 -translate-x-1/2 w-80 z-30 pointer-events-none flex flex-col justify-center">
                <div className="bg-[#0f0f16]/90 backdrop-blur-xl rounded-2xl border border-white/10 p-4 flex flex-col shadow-2xl pointer-events-auto max-h-[80%] overflow-hidden">
                    <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2 border-b border-white/5 pb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-green-400" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" /></svg>
                        AI SUGGESTIONS
                    </h3>

                    {deckAFile ? (
                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
                            {suggestions.map(({ file, analysis }) => (
                                <div 
                                    key={file.id} 
                                    onClick={() => setDeckBFileId(file.id)}
                                    className="p-2 rounded-lg bg-white/5 hover:bg-white/10 cursor-pointer transition-colors border border-transparent hover:border-cyan-500/30 group"
                                >
                                    <div className="flex items-center gap-2 mb-1">
                                        <AlbumCover tags={file.fetchedTags || file.originalTags} className="w-8 h-8 rounded" />
                                        <div className="flex-1 min-w-0">
                                            <div className="text-xs font-bold text-white truncate">{file.fetchedTags?.title || file.file.name}</div>
                                            <div className="text-[10px] text-slate-400 truncate">{file.fetchedTags?.artist}</div>
                                        </div>
                                    </div>
                                    <div className={`text-[9px] font-bold px-2 py-0.5 rounded flex justify-between items-center ${analysis.bgColor} ${analysis.color}`}>
                                        <span>{analysis.type}</span>
                                        <span>{analysis.score}%</span>
                                    </div>
                                </div>
                            ))}
                            {suggestions.length === 0 && (
                                <p className="text-xs text-slate-500 text-center mt-4">Brak idealnych dopasowań.</p>
                            )}
                        </div>
                    ) : (
                        <div className="flex-1 flex items-center justify-center text-xs text-slate-500 text-center px-4">
                            Włącz utwór na Decku A, aby zobaczyć sugestie AI.
                        </div>
                    )}
                </div>
            </div>

            <Deck id="B" label="DECK B" file={deckBFile} isMain={false} isPlayingNow={isPlaying && deckBFile?.id === playingFileId} />
        </div>

        {/* Mixer Controls - Fixed Bottom */}
        <div className="absolute bottom-0 w-full">
            <Mixer />
        </div>

        <style>{`
            .animate-spin-slow {
                animation: spin 4s linear infinite;
            }
        `}</style>
    </div>
  );
};

export default LiveDJTab;
