import React, { useState, useRef, useMemo } from 'react';
import { AudioFile } from '../types';
import { analyzeImageForVibe } from '../utils/services/aiService';
import AlbumCover from './AlbumCover';

interface VisualVibeModalProps {
  isOpen: boolean;
  onClose: () => void;
  files: AudioFile[];
  onCreatePlaylist: (name: string, trackIds: string[]) => void;
}

interface AnalysisResult {
    moodDescription: string;
    suggestedGenres: string[];
    suggestedKeywords: string[];
    colorPalette: string[];
}

const VisualVibeModal: React.FC<VisualVibeModalProps> = ({ isOpen, onClose, files, onCreatePlaylist }) => {
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [matchedTracks, setMatchedTracks] = useState<AudioFile[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const availableGenres = useMemo(() => {
      const genres = new Set<string>();
      files.forEach(f => {
          const g = f.fetchedTags?.genre || f.originalTags?.genre;
          if (g) genres.add(g);
      });
      return Array.from(genres);
  }, [files]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          setImage(file);
          setPreviewUrl(URL.createObjectURL(file));
          setResult(null);
          setMatchedTracks([]);
      }
  };

  const handleAnalyze = async () => {
      if (!image) return;
      setIsAnalyzing(true);
      try {
          const data = await analyzeImageForVibe(image, availableGenres);
          setResult(data);

          // Filter tracks based on result
          const keywords = [...(data.suggestedGenres || []), ...(data.suggestedKeywords || [])].map(k => k.toLowerCase());

          const matches = files.filter(f => {
              const tags = f.fetchedTags || f.originalTags;
              const text = `${tags.genre} ${tags.mood} ${tags.title} ${tags.comments}`.toLowerCase();
              // Check if any keyword is present
              return keywords.some(k => text.includes(k));
          });

          // Randomize and limit to 20 for a playlist
          setMatchedTracks(matches.sort(() => 0.5 - Math.random()).slice(0, 20));

      } catch (e) {
          alert("Błąd analizy obrazu.");
          console.error(e);
      } finally {
          setIsAnalyzing(false);
      }
  };

  const handleCreatePlaylist = () => {
      if (matchedTracks.length === 0) return;
      const moodName = result?.suggestedKeywords[0] || "Visual Vibe";
      const name = `Vibe: ${moodName} Mix`;
      onCreatePlaylist(name, matchedTracks.map(f => f.id));
      onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-sm flex justify-center items-center z-[80]" onClick={onClose}>
      <div 
        className="bg-[#0a0a0f] border border-white/10 rounded-2xl shadow-2xl w-full max-w-5xl h-[85vh] flex overflow-hidden animate-fade-in-scale"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Left Side: Image Upload */}
        <div className="w-1/3 bg-[#111] p-6 flex flex-col border-r border-white/5 relative">
            <h2 className="text-xl font-bold text-white neon-text-pink mb-6 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                Visual Vibe
