                                        <div className="text-xs text-slate-400 truncate">{track.fetchedTags?.artist || 'Unknown'}</div>
                                    </div>
                                    <div className="text-xs text-slate-500 font-mono">
                                        {track.fetchedTags?.bpm ? `${track.fetchedTags.bpm} BPM` : ''}
                                    </div>
